import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Usage","description":"","frontmatter":{"title":"Usage","slug":"usage"},"headers":[],"relativePath":"account-hub/usage.md","filePath":"account-hub/usage.md"}'),n={name:"account-hub/usage.md"};function s(i,e,c,h,u,l){return t(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Branch Dashboard gives you insight into metrics that impact your Branch invoice.</p><p>You can use this information to measure utilization for the current month, so that you do not go over your allowed limits. It allows you to analyze trends from month to month.</p><p>Depending on your plan, the Branch Dashboard will reflect either your app’s <strong>monthly active users (MAU)</strong> count, or it will show <strong>volume credit</strong> usage.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Please note that this article explains the <a href="./branch-dashboard-overview.html">legacy Branch experience</a> of viewing usage, which is slated for deprecation.</p><p>In the <a href="./new-branch-overview.html">new version of Branch</a>, usage can be viewed under <strong>Account</strong> → <a href="./billing-usage-new.html"><strong>Billing</strong></a>.</p></div><h3 id="monthly-active-users" tabindex="-1">Monthly active users <a class="header-anchor" href="#monthly-active-users" aria-label="Permalink to &quot;Monthly active users&quot;">​</a></h3><p>MAU is the number of unique individuals that interact with your web or app properties on a monthly basis.</p><p>Branch calculates your MAU count, which can be useful for determining the effectiveness of your marketing campaigns for your app.</p><h3 id="volume-credits" tabindex="-1">Volume credits <a class="header-anchor" href="#volume-credits" aria-label="Permalink to &quot;Volume credits&quot;">​</a></h3><p>Volume credits correspond to the number of end-user actions tracked, attributed, and reported on in Branch.</p><h2 id="track-usage" tabindex="-1">Track usage <a class="header-anchor" href="#track-usage" aria-label="Permalink to &quot;Track usage&quot;">​</a></h2><p>The <a href="https://dashboard.branch.io/account-settings/usage" target="_blank" rel="noreferrer">Usage tab</a> is where you will find a historical 12-month view of your app’s usage.</p><p>For some users, this report will reflect your app’s <strong>monthly active users</strong>, while for others it will show <strong>volume credits</strong>.</p><p>You can export this information in PNG, XLS, SVG, or CSV format using the navigation drawer icon on the right.</p>',14)])])}const g=a(n,[["render",s]]);export{d as __pageData,g as default};
